import React from 'react'
import { Link } from 'react-router-dom'

export default function Header() {
    return (
        <div>
            <Link to="/">Home</Link>
            <Link to="/abo">Home Page</Link>
            <Link to="/about">About</Link>
        </div>
    )
}
